"use client";
import { userScheme } from "@/lib/validations";
import { zodResolver } from "@hookform/resolvers/zod";
import { redirect, useRouter } from "next/navigation";
import React, { useState } from "react";
import { useForm } from "react-hook-form";
import z from "zod";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "../ui/form";

import { IUserFormFields } from "@/lib/dummyData";
import Link from "next/link";
import { useNeedReceiptStore, useUserDataStore } from "@/store/userStore";
import { Input } from "../ui/input";

const KycForm = () => {
  const form = useForm<z.infer<typeof userScheme>>({
    resolver: zodResolver(userScheme),
    defaultValues: {
      firstName: "",
      lastName: "",
      contactNum: 0,
    },
  });
  const onSubmit = (values: z.infer<typeof userScheme>) => {
    console.log(values);
    // const result = await addProducts(values);
  };

  const { firstName, lastName, setFirstName, saveData, newData } =
    useUserDataStore();

  const status = useNeedReceiptStore((state) => state.receiptStatus);

  return status === "No" ? (
    redirect("/")
  ) : (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(onSubmit)}
        className="bg-[#f7f5dc] shadow-md rounded px-8 pt-6 pb-8 mb-4"
        method="POST"
      >
        <p className="md:text-2xl lg:text-3xl py-4">
          Let's Verify Your Account
        </p>
        <FormField
          control={form.control}
          name="firstName"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-md md:text-lg lg:text-xl">
                First Name
              </FormLabel>
              <FormControl>
                <Input type="text" className="border-2 border-[#000]" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <FormField
          control={form.control}
          name="lastName"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-md md:text-lg lg:text-xl">
                Last Name
              </FormLabel>
              <FormControl>
                <Input type="text" className="border-2 border-[#000]" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <FormField
          control={form.control}
          name="contactNum"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-md md:text-lg lg:text-xl">
                Contact Number
              </FormLabel>
              <FormControl>
                <Input type="number" className="border-2 border-[#000]" />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <Link
          onClick={() => saveData}
          rel="preload"
          href={"/cart"}
          className="py-2 px-4 rounded-md cursor-pointer text-white bg-[#216c58]"
        >
          Next
        </Link>
        {/* <Button type="submit" className="w-full cursor-pointer">
          NEXT
        </Button> */}
      </form>
    </Form>
  );
};

export default KycForm;
